mapper.select:
SELECT id, project_id, page_name, sort_order, background_color, created_at, updated_at
FROM ad_page WHERE project_id = #{projectId}
ORDER BY sort_order ASC

mapper.update:
UPDATE ad_page
SET page_name = #{pageName},
    sort_order = #{sortOrder},
    background_color = #{backgroundColor}
WHERE id = #{id}
